// Функция конвертации Markdown в HTML
function markdownToHtml(markdown) {
    let html = markdown;
    // H1 заголовки
    html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
    // H2 заголовки
    html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
    // H3 заголовки
    html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
    // H4 заголовки
    html = html.replace(/^#### (.+)$/gm, '<h4>$1</h4>');
    // Жирный текст
    html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    // Курсив
    html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
    // Списки (ul)
    html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
    // Эмодзи списки
    html = html.replace(/^✅ (.+)$/gm, '<p>✅ $1</p>');
    html = html.replace(/^⚠️ (.+)$/gm, '<p>⚠️ $1</p>');
    html = html.replace(/^💪 (.+)$/gm, '<p>💪 $1</p>');
    html = html.replace(/^🎯 (.+)$/gm, '<p>🎯 $1</p>');
    html = html.replace(/^💡 (.+)$/gm, '<p>💡 $1</p>');
    html = html.replace(/^💬 (.+)$/gm, '<p>💬 $1</p>');
    html = html.replace(/^📸 (.+)$/gm, '<p>📸 $1</p>');
    // Нумерованные списки
    html = html.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');
    // Параграфы - обрабатываем по блокам
    const blocks = html.split('\n\n');
    html = blocks.map(block => {
        // Пропускаем блоки, которые уже являются HTML-тегами
        if (block.startsWith('<h') || block.startsWith('<ul') || block.startsWith('<ol') ||
            block.startsWith('<li') || block.startsWith('<hr') || block.startsWith('<p>')) {
            return block;
        }
        // Отдельная обработка для строк с эмодзи в начале
        if (/^[🌟💧🦴💪😊📐✨🧼⏱️📋🪞💋👁️💎🛌📚💬🛑🎉]/.test(block) && !block.startsWith('<')) {
            return block;
        }
        const trimmed = block.trim();
        if (trimmed && !trimmed.startsWith('<')) {
            return `<p>${trimmed}</p>`;
        }
        return trimmed;
    }).join('\n\n');
    // Группируем списки в <ul>
    html = html.replace(/(<li>.*?<\/li>\n?)+/g, '<ul>\n$&</ul>\n');
    // Горизонтальная линия
    html = html.replace(/^---$/gm, '<hr>');
    return html;
}
async function main() {
    try {
        // Connect to MongoDB
        const mongoUri = process.env.MONGODB_URI || 'mongodb://localhost:27017/rejuvena';
        console.log('🔌 Connecting to MongoDB...');
        await mongoose_1.default.connect(mongoUri);
        console.log('✅ Connected to MongoDB\n');
        // Update each day
        let updatedCount = 0;
        const daysToUpdate = [3, 4, 5, 6, 8, 9, 10, 12];
        for (const dayNumber of daysToUpdate) {
            const markdown = DAY_TEXTS[dayNumber];
            if (!markdown) {
                console.log(`⚠️ No text for day ${dayNumber}, skipping`);
                continue;
            }
            const html = markdownToHtml(markdown);
            console.log(`📝 Updating Day ${dayNumber}...`);
            console.log(`   Markdown length: ${markdown.length} chars`);
            console.log(`   HTML length: ${html.length} chars`);
            const day = await MarathonDay_model_1.default.findOneAndUpdate({
                marathonId: MARATHON_ID,
                dayNumber: dayNumber
            }, { description: html }, { new: true });
            if (day) {
                console.log(`✅ Day ${dayNumber} updated successfully`);
                updatedCount++;
            }
            else {
                console.log(`❌ Day ${dayNumber} not found`);
            }
            console.log('');
        }
        console.log(`\n🎉 Update complete! ${updatedCount}/${daysToUpdate.length} days updated.`);
        await mongoose_1.default.disconnect();
    }
    catch (error) {
        console.error('❌ Error:', error.message);
        process.exit(1);
    }
}
